import { useState } from 'react';
import ReactQuill from 'react-quill'
import 'react-quill/dist/quill.snow.css'

interface BlogProps {
    title: string,
    author: string,
    date: string,
    content: string
}

export const Blog = () => {
    const [title, setTitle] = useState('');
    const [author, setAuthor] = useState('');
    const [date, setDate] = useState('');
    const [content, setContent] = useState('');
    const [file, setFile] = useState<File | null>(null);

    const writeNewBlog = async (ev: { preventDefault: () => void; }) => {
        const data = new FormData();
        data.set('title', title);
        data.set('author', author);
        data.set('date', date);
        data.set('content', content);
        data.append('file', file)
        console.log(data)


        ev.preventDefault();
        console.log(file)

        await fetch('http://localhost:4000/write', {
                method: 'POST',
                body: data,
            });

        // try{
        //     const response = await fetch('http://localhost:4000/write', {
        //         method: 'POST',
        //         body: data,
        //     });
        //     if (response.ok) {
        //         alert("Successfully posted!");
        //     }
        //     else {
        //         alert("Failed to post :(")
        //     }
        // }
        // catch (ex) {
        //     console.error('Error: ', ex);
        // }
    }

    return (

        <div className="mt-5">
            <h2>Write a New Blog</h2>
                <form onSubmit={writeNewBlog}>
                <div className="form-row">
                    <div className="form-group col-md-8">
                        <input type="text" className="form-control" id="title" placeholder='Title' 
                            value={title} 
                            onChange={ev => setTitle(ev.target.value)}/>
                        </div>
                        <div className="form-group col-md-6">
                        <input type="text" className="form-control" id="author" placeholder='Author' 
                            value={author}
                            onChange={ev => setAuthor(ev.target.value)}/>
                    </div>
                </div>
                <div className="form-group col-md-6"> {/* col-md adjusts the horizontal size */}
                    <input type="file" className="form-control"
                    onChange={ev => setFile(ev.target.files ? ev.target.files[0] : null)}/>
                </div>
                <div className="form-group">
                    <input type="date" className="form-control" id="date" 
                    value={date}
                    onChange={ev => setDate(ev.target.value)}/>
                </div>
                <div className="form-group">
                    <ReactQuill 
                    value={content} 
                    onChange={newValue => setContent(newValue)}/> {/* npm install react-quill, an add-on for text box */}
                </div>
                <button type="submit" className="btn btn-primary">Create Post</button>
                </form>
        </div>
    )

}
